// Iteramos sobre todos los mensajes del lote diario
return $input.all().map(item => {
 // 1. Detectar adjuntos por content-type en vez de binary
  const contentType = item.json.headers['content-type'] || '';
  const hasAttachment = contentType.toLowerCase().includes('multipart/mixed');

  // 2. Limpieza de Ruido HTML
  // Quitamos bloques de estilo, scripts y tags para dejar solo el texto
  const rawHtml = item.json.html || "";
 // 1. Eliminamos bloques de código que no contienen texto visible (scripts, estilos, cabeceras)
  let cleanText = rawHtml.replace(/<(style|script|head|meta|title|noscript)[^>]*>[\s\S]*?<\/\1>/gi, '');

  // 2. Convertimos los tags HTML restantes en espacios
  cleanText = cleanText.replace(/<[^>]+>/g, ' ');

  // 3. ELIMINACIÓN UNIVERSAL DE ENTIDADES HTML
  // Esto busca cualquier cosa que empiece por '&' y termine en ';' y lo vuelve un espacio
  // (esto elimina &nbsp;, &aacute;, &amp;, etc., de golpe)
  cleanText = cleanText.replace(/&[a-z0-9#]+;/gi, ' ');

  // 4. LIMPIEZA DE ESPACIOS (El "super colapsador")
  // \s: espacios, tabs, saltos de linea
  // \u00A0: El código unicode del &nbsp; real
  // \u200B-\uFEFF: Caracteres de control invisibles
  cleanText = cleanText.replace(/[\s\u00A0\u200B\u200C\u200D\uFEFF]+/g, ' ');
  // 3. Decodificación de Headers (Asunto y Remitente)
  // Gmail a veces manda los headers encodeados en Base64/Quoted-Printable
  const decodeHeader = (str) => {
    if (!str) return "";
    try {
      // Intentamos una decodificación básica si viene con el formato =?UTF-8?B?...?=
      return str.replace(/=\?UTF-8\?B\?([^\?]+)\?=/gi, (match, p1) => Buffer.from(p1, 'base64').toString('utf8'));
    } catch (e) { return str; }
  };

  const subject = decodeHeader(item.json.subject);
  const from = decodeHeader(item.json.from.value[0].address);

  return {
    json: {
      id: item.json.id,
      from: from,
      subject: subject,
      // Recortamos a 2500 caracteres: suficiente para la IA, amable con tu bolsillo
      body_summary: cleanText.substring(0, 2500),
      hasAttachment: hasAttachment
    },
  };
});

// 1. Obtenemos los datos
let historicalData = [];
try {
  historicalData = $("Get History Memorial").all();
} catch (e) {
  historicalData = [];
}

const item = $input.item; 

// 2. Filtramos historial del remitente actual
const validHistory = historicalData.filter(h => 
  h.json && 
  Object.keys(h.json).length > 0 && 
  h.json.remitente === item.json.from // <--- ESTA ES LA MAGIA
);

// 3. Construimos el string con los ejemplos específicos
const historialStr = validHistory.length > 0 
  ? validHistory.map(h => `- Categoría: ${h.json.categoria} | Resumen: ${h.json.patron} | Es Manual: ${h.json.is_manual}`).join('\n') 
  : "No hay historial previo para este remitente específico.";

// 4. Armamos el prompt final
const finalPrompt = `
### CONTEXTO DE REFERENCIA (MEMORIA) ###
${historialStr}

### DATOS DEL CORREO ACTUAL ###
- ASUNTO: ${item.json.subject}
- CUERPO: ${item.json.body_summary}
- ADJUNTO (PDF): ${item.json.hasAttachment ? "Sí, pero no descargado aún." : "No tiene adjunto."}

### TAREA ###
Analiza el correo actual basándote en el historial (si existe). 
Si el remitente ya fue clasificado antes, intenta mantener la coherencia. Tienen prioridad los que fueron clasificados manualmente.
Responde siguiendo el formato JSON solicitado anteriormente.
`;

return {
  json: {
    id: item.json.id,
    from: item.json.from,
    subject: item.json.subject,
    hasAttachment: item.json.hasAttachment,
    body: item.json.body_summary,
    ia_prompt: finalPrompt
  }
};

const mails = $input.all();
const whitelist = $('Get White List').all();

return mails.map(item => {
  const isWhitelisted = whitelist.some(w => 
    item.json.From?.toLowerCase().includes(w.json.Remitente?.toLowerCase())
  );
  return { json: { ...item.json, isWhitelisted } };
});

const item = $input.item;
const loopItem = $('Loop 3 pending').item;

// ia_prompt y datos del mail SIEMPRE vienen del loop
const hasError = !!item.json.error;
const pdfText = hasError 
  ? "No se pudo extraer texto del PDF." 
  : (item.json.text || "No se pudo extraer texto del PDF.");

return {
  json: {
