    hasAttachment: false,
    ia_prompt: loopItem.json.ia_prompt.replace(
      "ADJUNTO (PDF): Sí, pero no descargado aún.",
      `CONTENIDO DEL ADJUNTO PDF:\n${pdfText.substring(0, 2000)}`
    )
  }
};

const items = $input.all();
const data = items[0]?.json;

const total_entrada   = data.total_entrada || 0;
const total_procesados = data.total_procesados || 0;

const hay_discrepancia = total_entrada !== total_procesados;
const discrepancia = total_entrada - total_procesados;

const detalle_categorias = Object.entries(data.detalle_categorias || {}).map(([categoria, total]) => ({ categoria, total }));
const detalle_fuentes = Object.entries(data.detalle_fuentes || {}).map(([fuente, total]) => ({ fuente, total }));

return [{
  json: {
    validacion: {
      hay_discrepancia,
      total_entrada,
      total_procesados,
      discrepancia,
      explicacion: hay_discrepancia 
        ? `Se perdieron ${Math.abs(discrepancia)} emails durante el procesamiento` 
        : 'Todos los emails fueron procesados correctamente'
    },
    detalle_categorias,
    detalle_fuentes,
    timestamp: new Date().toISOString()
  }
}];

